insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'name-recognition', '11111111-1111-1111-1111-111111111111', 'Name recognition', 'obedience', 'locked', ARRAY[]::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Charge the name","successCriteria":"Turns head toward handler on name 8 of 10 reps in a quiet room","sessionsRequired":2,"completedSessions":0},{"title":"Add distance and distraction","successCriteria":"Orients to name from across the room with mild distraction present","sessionsRequired":3,"completedSessions":0},{"title":"Generalize outside","successCriteria":"Responds to name outdoors on leash 8 of 10 reps","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog Their Name","type":"article","url":"https://www.akc.org/expert-advice/training/how-to-teach-dog-name/","publisher":"AKC"},{"title":"Name recognition foundation game","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+puppy+name+recognition","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Reliable orientation to the puppy''s name is the first building block every later cue depends on, since a dog can''t respond to instruction it isn''t already listening for.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'food-lure', '11111111-1111-1111-1111-111111111111', 'Food lure mechanics', 'obedience', 'locked', ARRAY[]::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Nose-follows-hand","successCriteria":"Tracks a treat in a closed fist through a simple path 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Lure into basic position shifts","successCriteria":"Follows lure into a sit or a turn without freezing or jumping","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"Lure-and-reward training plan","type":"plan","url":"https://www.akc.org/expert-advice/training/lure-reward-training/","publisher":"AKC"},{"title":"Lure training fundamentals","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+lure+training+fundamentals+puppy","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Clean lure mechanics (steady hand, correct pace, timely release) are the mechanical skill behind sit, down, touch, shake, spin, and roll over, so it is worth teaching as its own milestone before those cues stack on top of it.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'focus', '11111111-1111-1111-1111-111111111111', 'Focus / engagement', 'obedience', 'locked', ARRAY['name-recognition']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Eye contact for a treat","successCriteria":"Offers voluntary eye contact 8 of 10 reps indoors","sessionsRequired":2,"completedSessions":0},{"title":"Hold eye contact briefly","successCriteria":"Holds eye contact 3 seconds before reward","sessionsRequired":3,"completedSessions":0},{"title":"Focus around mild distraction","successCriteria":"Re-engages with handler within 2 seconds of a mild distraction outdoors","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Grab & Hold Your Dog''s Attention With the \"Watch Me\" Command","type":"article","url":"https://www.akc.org/expert-advice/training/watch-me-command-grab-dogs-attention/","publisher":"AKC"},{"title":"How to Train Your Dog to Stay Focused Around Distractions","type":"article","url":"https://www.akc.org/expert-advice/training/training-dogs-to-ignore-distractions/","publisher":"AKC"},{"title":"Engagement and focus training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+engagement+focus+training+puppy","publisher":"Kikopup"}]'::jsonb, 'Builds on name recognition by teaching sustained voluntary attention, which down, stay, spin, heel, and impulse control all rely on to hold the dog''s attention through a full behavior.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'impulse-control', '11111111-1111-1111-1111-111111111111', 'Impulse control', 'obedience', 'locked', ARRAY['focus']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"It''s Yer Choice / bowl game","successCriteria":"Waits without lunging while food bowl lowers 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Wait at doorway / crate","successCriteria":"Holds position while door opens until released","sessionsRequired":3,"completedSessions":0},{"title":"Settle during play arousal","successCriteria":"Interrupts play and offers a sit within 3 seconds of cue","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Impulse Control for Dogs: Dog Self-Control Training","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-your-dog-self-control/","publisher":"AKC"},{"title":"Impulse control games","type":"video","url":"https://www.youtube.com/results?search_query=impulse+control+games+for+puppies+positive+training","publisher":"YouTube training library"},{"title":"Training games for dogs","type":"article","url":"https://www.akc.org/expert-advice/training/training-games-for-dogs/","publisher":"AKC"}]'::jsonb, 'Extends focus into self-restraint around real motivators (food, doors, arousal), and is the readiness gate leave-it and wait depend on before they can be proofed in daily life.'
