insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'drop-it', '11111111-1111-1111-1111-111111111111', 'Drop it', 'obedience', 'locked', ARRAY['marker-word', 'food-lure']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Trade for low-value toy","successCriteria":"Releases a low-value toy for a treat trade 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue","successCriteria":"Drops item on verbal cue before treat is shown 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Proof with higher-value items","successCriteria":"Drops a favorite toy or found object on first cue without chase","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Drop It","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-your-dog-to-drop-it/","publisher":"AKC"},{"title":"Drop it without a chase","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+drop+it+trade+training","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Teaches a fair trade instead of a grab, which prevents resource guarding and is required before leave-it (impulse control around items already in the mouth) and retrieve (releasing the toy into the handler''s hand).'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'recall-foundation', '11111111-1111-1111-1111-111111111111', 'Recall foundation (come when called)', 'obedience', 'locked', ARRAY['name-recognition', 'marker-word']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Come for a treat, no distance","successCriteria":"Runs to handler from 3 feet on cue 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add distance indoors","successCriteria":"Recalls across a room away from mild distraction","sessionsRequired":3,"completedSessions":0},{"title":"Backyard recall","successCriteria":"Recalls from 15 feet outdoors on first cue 8 of 10 reps","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Reliable Recall: Teaching Your Dog to Always Come When Called","type":"article","url":"https://www.akc.org/expert-advice/training/reliable-recall-train-dogs-to-come-when-called/","publisher":"AKC"},{"title":"Recall foundation games","type":"video","url":"https://www.youtube.com/results?search_query=zak+george+puppy+recall+foundation","publisher":"Zak George"},{"title":"Games for building reliable recall behavior","type":"plan","url":"https://www.whole-dog-journal.com/training/leash_training/games-for-building-reliable-recall-behavior-for-your-dog/","publisher":"Whole Dog Journal"}]'::jsonb, 'Establishes the basic come-when-called response in low-distraction settings, which loose leash walking, dog park readiness, and later advanced/emergency recall all build distance and distraction on top of.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'outside-confidence', '11111111-1111-1111-1111-111111111111', 'Outside confidence', 'confidence', 'locked', ARRAY['name-recognition']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Front yard exposure","successCriteria":"Explores front yard with loose body language for 5 minutes","sessionsRequired":3,"completedSessions":0},{"title":"Novel surfaces and sounds","successCriteria":"Recovers within 5 seconds after a mild startle outdoors","sessionsRequired":4,"completedSessions":0},{"title":"Quiet street exposure","successCriteria":"Walks past a passing car or jogger without freezing or bolting","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Confident Puppy: How Do You Raise a Secure Young Dog","type":"article","url":"https://www.akc.org/expert-advice/training/how-do-you-raise-a-confident-puppy/","publisher":"AKC"},{"title":"Puppy Socialization: Why, When, and How to Do It Right","type":"plan","url":"https://www.akc.org/expert-advice/training/puppy-socialization/","publisher":"AKC"},{"title":"Building outdoor confidence in puppies","type":"video","url":"https://www.youtube.com/results?search_query=puppy+outdoor+confidence+building+socialization","publisher":"YouTube behavior library"}]'::jsonb, 'Builds calm, curious body language in outdoor environments before leash pressure and traffic are added, which loose leash walking depends on to avoid pairing the leash itself with stress.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
