insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'dog-body-language', '11111111-1111-1111-1111-111111111111', 'Reading dog body language', 'socialization', 'locked', ARRAY[]::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Identify calm vs. stiff body signals","successCriteria":"Handler correctly labels loose vs. tense body language in 8 of 10 photos or clips","sessionsRequired":2,"completedSessions":0},{"title":"Live observation at distance","successCriteria":"Handler flags a stress signal in a real dog interaction within 3 seconds","sessionsRequired":3,"completedSessions":0},{"title":"Apply during a supervised greeting","successCriteria":"Handler interrupts a greeting before escalation using body-language cues","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"Dog Body Language","type":"article","url":"https://www.akc.org/expert-advice/training/dog-body-language/","publisher":"AKC"},{"title":"7 Tips: Canine Body Language","type":"article","url":"https://www.aspcapro.org/resource/7-tips-canine-body-language","publisher":"ASPCA"},{"title":"Reading dog body language and play signals","type":"video","url":"https://www.youtube.com/results?search_query=dog+body+language+play+signals+training","publisher":"YouTube behavior library"}]'::jsonb, 'This is a handler skill, not a dog skill: recognizing stress and play signals is what makes dog park readiness and any dog-to-dog introduction safe to attempt, since escalation must be caught before it happens.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'stay', '11111111-1111-1111-1111-111111111111', 'Stay', 'obedience', 'locked', ARRAY['sit', 'focus']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Stay 3 seconds, handler stationary","successCriteria":"Holds sit-stay 3 seconds with handler at arm''s length 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Add duration and distance","successCriteria":"Holds stay 15 seconds with handler 6 feet away","sessionsRequired":4,"completedSessions":0},{"title":"Add distraction","successCriteria":"Holds stay through a mild distraction (dropped object, passerby) until released","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Stay","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-stay/","publisher":"AKC"},{"title":"Stay with duration and distraction","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+stay+duration+distraction","publisher":"Kikopup"},{"title":"Training ''stay'' vs. ''wait''","type":"article","url":"https://www.vet.cornell.edu/departments-centers-and-institutes/riney-canine-health-center/canine-health-information/training-stay-vs-wait","publisher":"Cornell Riney Canine Health Center"}]'::jsonb, 'Layers duration on top of a reliable sit and the focus needed to hold it, and becomes the foundation for place and advanced recall (a dog must reliably hold position before being released to come).'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'wait', '11111111-1111-1111-1111-111111111111', 'Wait', 'obedience', 'locked', ARRAY['impulse-control', 'sit']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Wait at bowl","successCriteria":"Waits without breaking while bowl is set down, released on cue","sessionsRequired":2,"completedSessions":0},{"title":"Wait at door","successCriteria":"Waits at threshold while door opens fully, released on cue","sessionsRequired":3,"completedSessions":0},{"title":"Wait at car / curb","successCriteria":"Waits before exiting car or crossing curb until released","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Wait at Doorways","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-wait-at-doorways/","publisher":"AKC"},{"title":"Training your dog to ''wait'' and ''stay''","type":"plan","url":"https://www.whole-dog-journal.com/behavior/training-your-dog-to-wait-and-stay/","publisher":"Whole Dog Journal"},{"title":"Wait command training","type":"video","url":"https://www.youtube.com/results?search_query=teach+dog+wait+at+door+command","publisher":"YouTube training library"}]'::jsonb, 'A lighter-weight cousin of stay focused on momentary impulse control at thresholds (doors, cars, curbs), so it depends on impulse control and a working sit rather than full stay duration.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'heel', '11111111-1111-1111-1111-111111111111', 'Heel', 'obedience', 'locked', ARRAY['loose-leash', 'focus']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Position at the leg indoors","successCriteria":"Holds heel position for 10 steps indoors with lure","sessionsRequired":3,"completedSessions":0},{"title":"Fade lure, add turns","successCriteria":"Maintains heel position through 2 turns without a lure","sessionsRequired":4,"completedSessions":0},{"title":"Proof outdoors with distraction","successCriteria":"Holds heel position for 30 feet past a mild distraction","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"Teach a Dog to Heel: How to Train a Dog to Walk Beside You","type":"article","url":"https://www.akc.org/expert-advice/training/heeling-teach-dog-walk/","publisher":"AKC"},{"title":"Heel position training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+heel+position+training","publisher":"Kikopup"},{"title":"Training games for dogs","type":"article","url":"https://www.akc.org/expert-advice/training/training-games-for-dogs/","publisher":"AKC"}]'::jsonb, 'A precise, structured version of loose leash walking that also requires strong focus, since the dog must hold a specific position relative to the handler rather than just avoid pulling.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'touch', '11111111-1111-1111-1111-111111111111', 'Touch (hand target)', 'obedience', 'locked', ARRAY['marker-word', 'food-lure']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Nose to palm","successCriteria":"Touches nose to open palm 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue and distance","successCriteria":"Moves 3 feet to touch palm on cue alone","sessionsRequired":3,"completedSessions":0},{"title":"Use touch to redirect","successCriteria":"Redirects away from a mild distraction using touch cue 8 of 10 reps","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Nose Target or ''Touch''","type":"article","url":"https://www.akc.org/expert-advice/training/teach-dog-nose-target-touch/","publisher":"AKC"},{"title":"Hand targeting foundation","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+hand+targeting+touch+training","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'A simple, high-value target behavior built on marker timing and lure mechanics that becomes the building block for fetch (targeting an object) and for redirecting attention in distracting environments.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'place', '11111111-1111-1111-1111-111111111111', 'Place / go-to-mat', 'obedience', 'locked', ARRAY['down', 'stay']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Lure onto mat","successCriteria":"Steps all four paws onto mat and sits or downs 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Send from a short distance","successCriteria":"Runs to mat and settles from 6 feet away on cue","sessionsRequired":4,"completedSessions":0},{"title":"Hold place through household activity","successCriteria":"Stays on mat through doorbell or meal prep until released","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"How To Teach Your Dog To Go to Their Place","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-go-to-your-place/","publisher":"AKC"},{"title":"Place / go-to-mat training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+go+to+mat+place+training","publisher":"Kikopup"},{"title":"Training games for dogs","type":"article","url":"https://www.akc.org/expert-advice/training/training-games-for-dogs/","publisher":"AKC"}]'::jsonb, 'Combines a settled down with stay-level duration on a specific target, making it a practical tool for managing greetings and mealtimes once both prerequisite skills are solid.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'speak', '11111111-1111-1111-1111-111111111111', 'Speak', 'obedience', 'locked', ARRAY['marker-word']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Capture and mark a bark","successCriteria":"Marks and rewards a spontaneous single bark 5 times in a session","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue","successCriteria":"Barks once within 3 seconds of cue 8 of 10 reps","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"''Speak!'' Training Your Dog to Bark on Command","type":"article","url":"https://www.akc.org/expert-advice/training/train-your-dog-to-speak/","publisher":"AKC"},{"title":"Teach speak on cue","type":"video","url":"https://www.youtube.com/results?search_query=teach+dog+speak+bark+on+command+positive+training","publisher":"YouTube training library"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Putting barking on a deliberate cue relies only on solid marker timing, and it sets up quiet as a natural next step since the two behaviors are trained as a pair.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'quiet', '11111111-1111-1111-1111-111111111111', 'Quiet', 'obedience', 'locked', ARRAY['speak']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Mark silence after a bark","successCriteria":"Rewards 2 seconds of silence immediately following a cued bark 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue and extend duration","successCriteria":"Stops barking within 3 seconds of cue and holds silence 10 seconds","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Expert Tips to Help Curb Excessive Dog Barking","type":"article","url":"https://www.akc.org/expert-advice/training/curb-excessive-dog-barking/","publisher":"AKC"},{"title":"Teach quiet on cue","type":"video","url":"https://www.youtube.com/results?search_query=teach+dog+quiet+command+stop+barking+positive+training","publisher":"YouTube training library"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Quiet is easiest to train once barking is already on a cue via speak, since the handler can prompt a bark and then reward the stop rather than waiting for random barking to interrupt.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'shake', '11111111-1111-1111-1111-111111111111', 'Shake', 'obedience', 'locked', ARRAY['marker-word', 'food-lure']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Capture the paw lift","successCriteria":"Paws at closed hand and gets marked/rewarded 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue","successCriteria":"Offers paw on cue alone without hand presented first","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How To Teach a Dog to Shake Hands","type":"article","url":"https://www.akc.org/expert-advice/training/how-to-teach-your-dog-to-shake-hands/","publisher":"AKC"},{"title":"Teach shake without hand manipulation","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+shake+paw+trick","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'A simple capture-and-lure trick that reinforces clean marker timing and lure fading, giving an easy early win once the mechanical foundations are in place.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'spin', '11111111-1111-1111-1111-111111111111', 'Spin', 'obedience', 'locked', ARRAY['food-lure', 'focus']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Lure a full circle","successCriteria":"Follows lure through a 360-degree turn 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Fade lure, add cue, both directions","successCriteria":"Spins in either direction on verbal cue without a visible lure","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Spin Around","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-spin-around/","publisher":"AKC"},{"title":"Spin trick training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+spin+trick","publisher":"Kikopup"},{"title":"Advanced dog tricks","type":"article","url":"https://www.akc.org/expert-advice/training/advanced-dog-tricks/","publisher":"AKC"}]'::jsonb, 'Builds directly on lure-following mechanics and requires sustained focus to complete a full circle without breaking off, making it a natural next trick once both are solid.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'roll-over', '11111111-1111-1111-1111-111111111111', 'Roll over', 'obedience', 'locked', ARRAY['down', 'food-lure']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Lure from down to side","successCriteria":"Follows lure from down into a side-lie 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Complete the roll","successCriteria":"Completes a full roll from lure with verbal cue paired","sessionsRequired":3,"completedSessions":0},{"title":"Fade lure","successCriteria":"Rolls over on verbal cue alone 8 of 10 reps","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach a Dog to Roll Over","type":"article","url":"https://www.akc.org/expert-advice/training/how-to-teach-a-dog-to-roll-over/","publisher":"AKC"},{"title":"Roll over trick training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+roll+over+trick","publisher":"Kikopup"},{"title":"Advanced dog tricks","type":"article","url":"https://www.akc.org/expert-advice/training/advanced-dog-tricks/","publisher":"AKC"}]'::jsonb, 'Starts from a settled down and uses the same lure-following skill as spin, just guided along the ground instead of in a circle, so a comfortable down is a prerequisite.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'play-dead', '11111111-1111-1111-1111-111111111111', 'Play dead', 'obedience', 'locked', ARRAY['down']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Lure onto side from down","successCriteria":"Falls onto side from a down position 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Add cue and hold briefly","successCriteria":"Holds the side-lie 3 seconds on verbal cue before release word","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Play Dead","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-play-dead/","publisher":"AKC"},{"title":"Play dead trick training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+play+dead+trick","publisher":"Kikopup"},{"title":"Advanced dog tricks","type":"article","url":"https://www.akc.org/expert-advice/training/advanced-dog-tricks/","publisher":"AKC"}]'::jsonb, 'Explicitly requires a known down cue as the starting position before the side-lie and hold can be layered on top, per standard trick-training progression.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'fetch', '11111111-1111-1111-1111-111111111111', 'Fetch', 'obedience', 'locked', ARRAY['touch', 'impulse-control']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Chase and grab a tossed toy","successCriteria":"Chases and picks up a tossed toy 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Bring toy back toward handler","successCriteria":"Returns toy to within arm''s reach of handler 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Full fetch loop with release","successCriteria":"Completes toss-chase-return-release loop 5 times in a row without chasing","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Fetch","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-fetch/","publisher":"AKC"},{"title":"Two-toy fetch training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+teach+dog+fetch+two+toy+method","publisher":"Kikopup"},{"title":"Training games for dogs","type":"article","url":"https://www.akc.org/expert-advice/training/training-games-for-dogs/","publisher":"AKC"}]'::jsonb, 'Uses hand-targeting drive toward an object plus enough impulse control to bring the toy back rather than keep-away, making both prerequisite skills load-bearing for a clean return.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'retrieve', '11111111-1111-1111-1111-111111111111', 'Formal retrieve', 'obedience', 'locked', ARRAY['fetch', 'drop-it']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Hold and carry","successCriteria":"Holds a toy in mouth for 5 seconds while walking beside handler","sessionsRequired":3,"completedSessions":0},{"title":"Deliver to hand","successCriteria":"Releases toy directly into handler''s hand on cue 8 of 10 reps","sessionsRequired":4,"completedSessions":0},{"title":"Retrieve a dropped item on request","successCriteria":"Picks up and delivers a named household item to hand 7 of 10 reps","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Fetch","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-fetch/","publisher":"AKC"},{"title":"Formal retrieve with hold and deliver","type":"video","url":"https://www.youtube.com/results?search_query=formal+retrieve+hold+and+deliver+dog+training","publisher":"YouTube training library"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Extends casual fetch into a controlled hold-and-deliver behavior, which requires the clean release taught in drop it so the dog gives up the item into a hand instead of dropping it on the ground.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'advanced-recall', '11111111-1111-1111-1111-111111111111', 'Advanced recall', 'obedience', 'locked', ARRAY['recall-foundation', 'stay']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Recall away from a stay","successCriteria":"Breaks a stay and recalls immediately on cue 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Recall with moderate distraction","successCriteria":"Recalls past a person, toy, or food distraction at 10 feet","sessionsRequired":4,"completedSessions":0},{"title":"Long-line recall outdoors","successCriteria":"Recalls from 30+ feet on a long line in a new outdoor location 8 of 10 reps","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"How to Train Your Dog to Come When Called: Step-by-Step Recall","type":"article","url":"https://www.akc.org/expert-advice/training/reliable-recalls-how-to-train-your-dog-to-come-when-called/","publisher":"AKC"},{"title":"Advanced recall with distraction and distance","type":"video","url":"https://www.youtube.com/results?search_query=zak+george+advanced+recall+training+distractions","publisher":"Zak George"},{"title":"Why a reliable recall is so important","type":"plan","url":"https://www.whole-dog-journal.com/training/leash_training/why-a-reliable-recall-is-so-important/","publisher":"Whole Dog Journal"}]'::jsonb, 'Adds real distraction and distance on top of recall foundation, and requires stay so the dog has practice holding position under mild arousal before being asked to break it on cue.'
) on conflict (id) do nothing;

insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'emergency-recall', '11111111-1111-1111-1111-111111111111', 'Emergency recall', 'obedience', 'locked', ARRAY['recall-foundation', 'advanced-recall']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Condition a unique emergency cue","successCriteria":"Orients and sprints to handler on the special cue paired with a jackpot reward 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Proof under high distraction","successCriteria":"Responds to emergency cue within 2 seconds during active play or around another dog","sessionsRequired":4,"completedSessions":0},{"title":"Randomized real-world tests","successCriteria":"Responds successfully to 5 unannounced real-world tests across different locations","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog the Emergency Recall","type":"article","url":"https://www.preventivevet.com/dogs/teach-your-dog-the-emergency-recall-come","publisher":"Preventive Vet"},{"title":"Emergency recall conditioning","type":"video","url":"https://www.youtube.com/results?search_query=emergency+recall+training+dog+jackpot+cue","publisher":"YouTube training library"},{"title":"Reliable Recall: Teaching Your Dog to Always Come When Called","type":"article","url":"https://www.akc.org/expert-advice/training/reliable-recall-train-dogs-to-come-when-called/","publisher":"AKC"}]'::jsonb, 'Reserves a separate, never-poisoned cue with maximum reinforcement history for true emergencies, so it depends on both recall foundation and advanced-recall being solid before adding a dedicated life-or-death cue on top.'
) on conflict (id) do nothing;

